import{_ as l,o as i,c as e,a2 as s}from"./chunks/framework.DRBHoC6Q.js";const u=JSON.parse('{"title":"CEO 经营决策系统团队 Agent 交接说明","description":"","frontmatter":{},"headers":[],"relativePath":"v1/agent-handoff.md","filePath":"v1/agent-handoff.md","lastUpdated":1783323851000}'),n={name:"v1/agent-handoff.md"};function p(t,a,r,o,h,d){return i(),e("div",null,[...a[0]||(a[0]=[s(`<h1 id="ceo-经营决策系统团队-agent-交接说明" tabindex="-1">CEO 经营决策系统团队 Agent 交接说明 <a class="header-anchor" href="#ceo-经营决策系统团队-agent-交接说明" aria-label="Permalink to &quot;CEO 经营决策系统团队 Agent 交接说明&quot;">​</a></h1><h2 id="先读结论" tabindex="-1">先读结论 <a class="header-anchor" href="#先读结论" aria-label="Permalink to &quot;先读结论&quot;">​</a></h2><p>当前项目不是做“财务大屏”，也不是做“AI 财务助手”。</p><p>正确产品形态是：</p><blockquote><p>给 CEO / 企业经营者使用的经营决策系统。 规则负责算清楚，AI 负责讲明白、派下去、追到底，老板负责最终拍板。</p></blockquote><p>第一阶段只围绕 3 个问题做：</p><ol><li>未来现金流有没有缺口？</li><li>这笔钱现在该不该付？</li><li>发现风险后谁负责处理，处理到哪一步了？</li></ol><p>不要扩展员工 AI 工具、复杂审批流、通用问答助手、炫酷数据大屏。</p><h2 id="当前-demo-状态" tabindex="-1">当前 demo 状态 <a class="header-anchor" href="#当前-demo-状态" aria-label="Permalink to &quot;当前 demo 状态&quot;">​</a></h2><p>本地 demo 地址：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:5173/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>当前页面已经改成了正确方向：</p><ul><li>CEO 经营决策台</li><li>今日老板要拍板</li><li>30 / 60 / 90 天现金流</li><li>回款风险 Top 3</li><li>付款建议 Top 3</li><li>风险责任追踪</li></ul><p>这个形态基本达到老板演示要求。</p><p>但当前还不是可试点版本，因为部分数据仍是前端硬编码演示数据。</p><h2 id="当前主要问题" tabindex="-1">当前主要问题 <a class="header-anchor" href="#当前主要问题" aria-label="Permalink to &quot;当前主要问题&quot;">​</a></h2><h3 id="_1-首页部分数据还是硬编码" tabindex="-1">1. 首页部分数据还是硬编码 <a class="header-anchor" href="#_1-首页部分数据还是硬编码" aria-label="Permalink to &quot;1. 首页部分数据还是硬编码&quot;">​</a></h3><p>例如：</p><ul><li>60 天缺口 420 万</li><li>90 天恢复安全线</li><li>回款风险 Top 3</li><li>付款建议 Top 3</li><li>风险责任追踪</li></ul><p>这些内容不能长期写死在前端。下一步要接后端规则和样例数据。</p><h3 id="_2-ai-按钮还只是展示" tabindex="-1">2. AI 按钮还只是展示 <a class="header-anchor" href="#_2-ai-按钮还只是展示" aria-label="Permalink to &quot;2. AI 按钮还只是展示&quot;">​</a></h3><p>当前页面有：</p><ul><li>AI 解释原因</li><li>生成动作</li><li>生成老板复盘</li></ul><p>方向是对的，但要变成真实输出：</p><ul><li>点击后能看到基于数据和规则的解释</li><li>能生成派单话术</li><li>能生成老板复盘摘要</li><li>必须带数据来源和规则依据</li></ul><p>AI 不能替老板审批，不能凭空判断付款和投资。</p><h2 id="产品边界" tabindex="-1">产品边界 <a class="header-anchor" href="#产品边界" aria-label="Permalink to &quot;产品边界&quot;">​</a></h2><h3 id="要做" tabindex="-1">要做 <a class="header-anchor" href="#要做" aria-label="Permalink to &quot;要做&quot;">​</a></h3><p>做 CEO 每日经营决策台。</p><p>首页必须让老板 30 秒内知道：</p><ul><li>今天有什么风险</li><li>影响多少钱</li><li>谁负责</li><li>截止时间是什么</li><li>要不要老板拍板</li><li>下一步怎么处理</li></ul><h3 id="不做" tabindex="-1">不做 <a class="header-anchor" href="#不做" aria-label="Permalink to &quot;不做&quot;">​</a></h3><p>第一阶段不要做：</p><ul><li>员工岗位 AI 工具</li><li>漂亮但无决策价值的数据大屏</li><li>万能 AI 聊天助手</li><li>AI 自动决定付款</li><li>AI 自动决定组织责任</li><li>替代钉钉 / 飞书审批流</li><li>复杂权限系统</li><li>业务投资测算大模块</li></ul><p>业务投资测算可以放 P2，不要抢 P0。</p><h2 id="正确的信息架构" tabindex="-1">正确的信息架构 <a class="header-anchor" href="#正确的信息架构" aria-label="Permalink to &quot;正确的信息架构&quot;">​</a></h2><p>导航建议保持：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CEO 经营决策系统</span></span>
<span class="line"><span>├── 今日决策</span></span>
<span class="line"><span>├── 现金流</span></span>
<span class="line"><span>├── 回款风险</span></span>
<span class="line"><span>├── 付款判断</span></span>
<span class="line"><span>├── 风险任务</span></span>
<span class="line"><span>└── 数据与规则</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>其中前 5 个是老板视角。</p><p><code>数据与规则</code> 是后台支撑，不是主卖点，不要做成 CFO 并列产品。</p><h2 id="ceo-首页必须保留的-5-块" tabindex="-1">CEO 首页必须保留的 5 块 <a class="header-anchor" href="#ceo-首页必须保留的-5-块" aria-label="Permalink to &quot;CEO 首页必须保留的 5 块&quot;">​</a></h2><h3 id="_1-今日老板要拍板" tabindex="-1">1. 今日老板要拍板 <a class="header-anchor" href="#_1-今日老板要拍板" aria-label="Permalink to &quot;1. 今日老板要拍板&quot;">​</a></h3><p>每条事项必须包含：</p><ul><li>事项标题</li><li>影响金额</li><li>风险原因</li><li>责任人</li><li>截止时间</li><li>建议动作</li><li>查看依据</li><li>AI 解释 / 生成动作 / 生成复盘</li></ul><p>示例：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>水滴 300 万回款逾期，导致本月现金缺口扩大</span></span>
<span class="line"><span>影响：本月现金缺口 750 万</span></span>
<span class="line"><span>责任人：商务负责人 张三</span></span>
<span class="line"><span>截止：今日 18:00</span></span>
<span class="line"><span>建议：老板催办 / 升级处理</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="_2-30-60-90-天现金流" tabindex="-1">2. 30 / 60 / 90 天现金流 <a class="header-anchor" href="#_2-30-60-90-天现金流" aria-label="Permalink to &quot;2. 30 / 60 / 90 天现金流&quot;">​</a></h3><p>必须展示：</p><ul><li>30 天缺口</li><li>60 天缺口</li><li>90 天判断</li><li>最大缺口</li><li>缺口出现时间</li><li>主要原因</li><li>可延后付款</li><li>必须催回款</li></ul><p>现金流不是简单收入减支出，而是看时间节奏：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>钱什么时候出去</span></span>
<span class="line"><span>钱什么时候回来</span></span>
<span class="line"><span>中间有没有断档</span></span>
<span class="line"><span>需要准备多少现金</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="_3-回款风险-top-3" tabindex="-1">3. 回款风险 Top 3 <a class="header-anchor" href="#_3-回款风险-top-3" aria-label="Permalink to &quot;3. 回款风险 Top 3&quot;">​</a></h3><p>必须展示：</p><ul><li>客户 / 渠道</li><li>应回金额</li><li>应回日期</li><li>实收金额</li><li>逾期天数</li><li>责任人</li><li>当前处理状态</li></ul><p>核心场景：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每月 15 号该进账但没进账</span></span>
<span class="line"><span>→ 系统预警</span></span>
<span class="line"><span>→ 派给负责人</span></span>
<span class="line"><span>→ 超时升级</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="_4-付款建议-top-3" tabindex="-1">4. 付款建议 Top 3 <a class="header-anchor" href="#_4-付款建议-top-3" aria-label="Permalink to &quot;4. 付款建议 Top 3&quot;">​</a></h3><p>每笔付款必须给出建议，不要只给通过/拒绝。</p><p>建议枚举：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>可付</span></span>
<span class="line"><span>暂缓</span></span>
<span class="line"><span>补充依据</span></span>
<span class="line"><span>高风险</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>每条必须展示：</p><ul><li>付款事项</li><li>金额</li><li>建议</li><li>原因</li><li>付款依据是否完整</li><li>是否预算内</li><li>付款后对现金流影响</li><li>是否需要老板复核</li></ul><h3 id="_5-风险责任追踪" tabindex="-1">5. 风险责任追踪 <a class="header-anchor" href="#_5-风险责任追踪" aria-label="Permalink to &quot;5. 风险责任追踪&quot;">​</a></h3><p>每条风险必须展示：</p><ul><li>风险事项</li><li>责任人</li><li>截止时间</li><li>当前状态</li><li>是否超时</li><li>是否升级老板</li></ul><p>系统不能只预警，必须追踪闭环。</p><h2 id="ai-的正确位置" tabindex="-1">AI 的正确位置 <a class="header-anchor" href="#ai-的正确位置" aria-label="Permalink to &quot;AI 的正确位置&quot;">​</a></h2><p>AI 不是主入口，不要把首页做成大聊天框。</p><p>AI 应该嵌入每张风险卡，做 4 件事：</p><ol><li>解释为什么有风险</li><li>生成处理建议</li><li>生成派单内容</li><li>生成老板复盘</li></ol><p>原则：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>规则判断优先</span></span>
<span class="line"><span>AI 负责解释、归因、提醒、派单、复盘</span></span>
<span class="line"><span>老板做最终决策</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>AI 输出必须带：</p><ul><li>数据来源</li><li>规则依据</li><li>相关金额</li><li>责任人</li><li>下一步动作</li></ul><p>禁止输出无依据的“建议付款 / 建议投资”。</p><h2 id="数据资源要求" tabindex="-1">数据资源要求 <a class="header-anchor" href="#数据资源要求" aria-label="Permalink to &quot;数据资源要求&quot;">​</a></h2><p>先不要急着对接系统，先用表格跑通闭环。</p><p>需要准备 4 张表。</p><h3 id="_1-回款计划表" tabindex="-1">1. 回款计划表 <a class="header-anchor" href="#_1-回款计划表" aria-label="Permalink to &quot;1. 回款计划表&quot;">​</a></h3><p>字段：</p><ul><li>客户 / 渠道</li><li>应回金额</li><li>正常回款日</li><li>实际到账金额</li><li>逾期天数</li><li>负责人</li><li>合同 / 业务来源</li><li>当前状态</li></ul><h3 id="_2-付款申请表" tabindex="-1">2. 付款申请表 <a class="header-anchor" href="#_2-付款申请表" aria-label="Permalink to &quot;2. 付款申请表&quot;">​</a></h3><p>字段：</p><ul><li>付款事项</li><li>金额</li><li>收款方</li><li>付款原因</li><li>预算科目</li><li>是否刚性支出</li><li>是否有合同 / 发票 / 结算单</li><li>申请人</li><li>期望付款日期</li></ul><h3 id="_3-现金流基础表" tabindex="-1">3. 现金流基础表 <a class="header-anchor" href="#_3-现金流基础表" aria-label="Permalink to &quot;3. 现金流基础表&quot;">​</a></h3><p>字段：</p><ul><li>当前现金余额</li><li>固定支出</li><li>已确定支出</li><li>待审批支出</li><li>预计回款</li><li>安全现金线</li></ul><h3 id="_4-预算与规则表" tabindex="-1">4. 预算与规则表 <a class="header-anchor" href="#_4-预算与规则表" aria-label="Permalink to &quot;4. 预算与规则表&quot;">​</a></h3><p>字段：</p><ul><li>各类费用预算</li><li>付款审批阈值</li><li>现金缺口预警线</li><li>逾期风险规则</li><li>超时升级规则</li><li>通知对象</li><li>处理时限</li></ul><h2 id="开发优先级" tabindex="-1">开发优先级 <a class="header-anchor" href="#开发优先级" aria-label="Permalink to &quot;开发优先级&quot;">​</a></h2><h3 id="p0" tabindex="-1">P0 <a class="header-anchor" href="#p0" aria-label="Permalink to &quot;P0&quot;">​</a></h3><p>必须优先完成：</p><ol><li>CEO 每日决策台</li><li>30 / 60 / 90 天现金缺口</li><li>回款风险 Top 3</li><li>付款建议 Top 3</li><li>风险责任追踪</li><li>数据来源和规则依据</li></ol><h3 id="p1" tabindex="-1">P1 <a class="header-anchor" href="#p1" aria-label="Permalink to &quot;P1&quot;">​</a></h3><p>P0 跑通后再做：</p><ul><li>数据与规则后台</li><li>字段口径确认</li><li>预算阈值配置</li><li>待复核数据</li><li>任务派发 SOP</li><li>AI 复盘摘要</li></ul><h3 id="p2" tabindex="-1">P2 <a class="header-anchor" href="#p2" aria-label="Permalink to &quot;P2&quot;">​</a></h3><p>暂时不做或只做入口：</p><ul><li>业务投资回收测算</li><li>替代钉钉审批</li><li>复杂组织权限</li><li>多租户</li><li>通用 AI 助手</li></ul><h2 id="下一步工程任务" tabindex="-1">下一步工程任务 <a class="header-anchor" href="#下一步工程任务" aria-label="Permalink to &quot;下一步工程任务&quot;">​</a></h2><h3 id="任务-1-首页数据动态化" tabindex="-1">任务 1：首页数据动态化 <a class="header-anchor" href="#任务-1-首页数据动态化" aria-label="Permalink to &quot;任务 1：首页数据动态化&quot;">​</a></h3><p>把首页硬编码数据替换为 API 数据。</p><p>优先接：</p><ul><li>回款风险 Top 3 接回款风险接口</li><li>付款建议 Top 3 接付款判断接口或付款样例表</li><li>30 / 60 / 90 接现金流预测接口</li><li>风险责任追踪接任务状态数据</li></ul><p>验收：</p><p>页面刷新后，核心卡片来自接口或结构化样例数据，不再直接写死。</p><h3 id="任务-2-补-30-60-90-现金流判断" tabindex="-1">任务 2：补 30 / 60 / 90 现金流判断 <a class="header-anchor" href="#任务-2-补-30-60-90-现金流判断" aria-label="Permalink to &quot;任务 2：补 30 / 60 / 90 现金流判断&quot;">​</a></h3><p>输出必须包含：</p><ul><li>30 天缺口</li><li>60 天缺口</li><li>90 天判断</li><li>最大缺口</li><li>缺口出现时间</li><li>缺口原因</li><li>建议动作</li></ul><p>验收：</p><p>老板能直接看出未来是否断档，而不是只看到本月缺口。</p><h3 id="任务-3-付款建议标准化" tabindex="-1">任务 3：付款建议标准化 <a class="header-anchor" href="#任务-3-付款建议标准化" aria-label="Permalink to &quot;任务 3：付款建议标准化&quot;">​</a></h3><p>付款建议只能是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>可付 / 暂缓 / 补充依据 / 高风险</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>每笔付款必须输出：</p><ul><li>建议</li><li>原因</li><li>依据</li><li>预算影响</li><li>现金流影响</li><li>是否需要老板复核</li></ul><p>验收：</p><p>老板看到一笔付款后，能知道现在该不该付，以及为什么。</p><h3 id="任务-4-ai-解释弹层" tabindex="-1">任务 4：AI 解释弹层 <a class="header-anchor" href="#任务-4-ai-解释弹层" aria-label="Permalink to &quot;任务 4：AI 解释弹层&quot;">​</a></h3><p>把 AI 按钮做成真实弹层或侧边抽屉。</p><p>至少支持：</p><ul><li>AI 解释原因</li><li>生成动作</li><li>生成老板复盘</li></ul><p>输出必须基于当前卡片数据和规则依据。</p><p>验收：</p><p>不能出现空泛文案，必须引用金额、客户、付款事项、规则或数据来源。</p><h3 id="任务-5-风险任务闭环" tabindex="-1">任务 5：风险任务闭环 <a class="header-anchor" href="#任务-5-风险任务闭环" aria-label="Permalink to &quot;任务 5：风险任务闭环&quot;">​</a></h3><p>每个风险要有：</p><ul><li>责任人</li><li>截止时间</li><li>状态</li><li>最近处理记录</li><li>超时规则</li><li>升级对象</li></ul><p>验收：</p><p>系统能回答“风险谁处理，处理到哪一步了”。</p><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><p>这版不是看功能数量，而是看老板能不能 30 秒内回答：</p><ol><li>未来 30 / 60 / 90 天有没有现金缺口？</li><li>哪几笔钱该进没进？</li><li>哪几笔钱现在不能付？</li><li>哪个风险没人处理或已超时？</li><li>今天需要老板拍板什么？</li></ol><p>如果这 5 个问题答不出来，就是没做好。</p><h2 id="和团队沟通时的禁止跑偏项" tabindex="-1">和团队沟通时的禁止跑偏项 <a class="header-anchor" href="#和团队沟通时的禁止跑偏项" aria-label="Permalink to &quot;和团队沟通时的禁止跑偏项&quot;">​</a></h2><p>不要把它做成：</p><ul><li>普通 BI 大屏</li><li>财务报表系统</li><li>CFO 工作台</li><li>AI 聊天机器人</li><li>审批流系统</li><li>项目管理工具</li></ul><p>它是：</p><blockquote><p>CEO 经营决策台。 收入/回款、支出/付款、现金流缺口、风险责任、老板拍板，形成闭环。</p></blockquote>`,140)])])}const b=l(n,[["render",p]]);export{u as __pageData,b as default};
